const input = $input.item.json;
const problem = String(input.problem || '').toLowerCase();

let action = 'business_pro';
let system = input.recommendedSystem || 'Business Pro System';

if (problem.includes('pochi clienti') || problem.includes('acquisizione')) {
  action = 'acquisition';
  system = 'Acquisition System';
} else if (problem.includes('fidelizzare') || problem.includes('ritornano')) {
  action = 'retention';
  system = 'Retention System';
} else if (problem.includes('tempo') || problem.includes('manuale')) {
  action = 'automation';
  system = 'Automation System';
} else if (problem.includes('schede') || problem.includes('contenuti')) {
  action = 'content';
  system = 'Content System';
}

return [{
  json: {
    ...input,
    agent: 'business_agent',
    action,
    system,
    recommendedSystem: input.recommendedSystem || system,
    segment: 'business'
  }
}];

const source = $('Hermes Decision').item.json;
const rawContent = $json.choices?.[0]?.message?.content || $json.message?.content || $json.response || '';

function safeParse(value) {
  if (!value) return null;
  if (typeof value === 'object') return value;
  try {
    return JSON.parse(value);
  } catch (error) {
    const match = String(value).match(/\{[\s\S]*\}/);
    if (match) {
      try {
        return JSON.parse(match[0]);
      } catch (innerError) {}
    }
  }
  return null;
}

const parsed = safeParse(rawContent);
const subjectByAction = {
  acquisition: 'Migliora l acquisizione clienti della tua attivita vino',
  retention: 'Trasforma i contatti in clienti che ritornano',
  automation: 'Riduci il lavoro manuale e rendi il sistema piu efficiente',
  content: 'Rendi i tuoi contenuti vino piu utili e piu vendibili',
  business_pro: 'Costruiamo un sistema commerciale piu strutturato per il tuo business'
};

const fallbackSubject = subjectByAction[source.action] || 'Costruiamo il sistema giusto per il tuo business del vino';
const fallbackBody = `Ciao ${source.name || ''}, grazie per aver completato la diagnosi Divino. Il problema principale che emerge e ${source.problem || 'una crescita non ancora strutturata'}. Il sistema consigliato per te e ${source.recommendedSystem || source.system}. Se vuoi, possiamo confrontarci e costruire il prossimo passo piu adatto al tuo business del vino.`;
const fallbackNote = `Lead business da quiz. Azione suggerita: ${source.action}. Sistema: ${source.recommendedSystem || source.system}.`;
const fallbackNextAction = source.action === 'content' ? 'Inviare proposta contenuti e piano editoriale' : 'Proporre call diagnostica commerciale';

return [{
  json: {
    ...source,
    generatedSubject: parsed?.subject || fallbackSubject,
    generatedBody: parsed?.body || fallbackBody,
    internalNote: parsed?.internal_note || fallbackNote,
    nextAction: parsed?.next_action || fallbackNextAction
  }
}];
